# Security measures for pickle loading
class SafeUnpickler(pickle.Unpickler):
    """Custom unpickler with security restrictions."""
    
    def find_class(self, module, name):
        # Restrict allowed modules and classes
        allowed_modules = {
            '__builtin__', 'builtins', 'collections', 'datetime', 'json'
        }
        
        if module not in allowed_modules:
            raise pickle.UnpicklingError(f"Module not allowed: {module}")
            
        return super().find_class(module, name)

